export const DIGITS_NAME = 4;
export const DIGITS_PASSWORD = 6;
export const VALIDATE = RegExp(/^[a-zA-Z0-9.!#$%&’*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+(?:\.[a-zA-Z0-9-]+)*$/);
